import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest quote cases ===
  it.todo("empty item list → premium 5 G (only processing fee)");

  // === Base premiums for main items (with first-insurance surcharge and fee) ===
  it.todo("single sword (steel, ench 3, not cursed), new customer → premium 115 G (100 base + 10 first + 5 fee)");
  it.todo("single amulet (plain, new customer) → premium 71 G (60 base + 6 first + 5 fee)");
  it.todo("single staff (plain, new customer) → premium 93 G (80 base + 8 first + 5 fee)");
  it.todo("single potion (plain, new customer) → premium 49 G (40 base + 4 first + 5 fee)");

  // === Component base premiums and building block ===
  it.todo("2 runes (new customer) → base 50 G; premium 60 G (50 + 5 first + 5 fee)");
  it.todo("3 runes (block, new customer) → base 60 G; premium 71 G (60 + 6 first + 5 fee)");
  it.todo("4 runes (no block - requires exactly 3, new customer) → base 100 G; premium 115 G (100 + 10 first + 5 fee)");
  it.todo("7 runes (one block of 3 + 4 singles, new customer) → base 60+100=160 G; premium 181 G (160 + 16 first + 5 fee)");

  // === Alike components clarification ===
  it.todo("2 runes + 1 moonstone (no block, different types) → base 75 G; premium 88 G (75 + 8 first(rounded up) + 5 fee)");
  it.todo("3 runes + 3 moonstones (two separate blocks) → base 120 G; premium 137 G (120 + 12 first + 5 fee)");

  // === Cursed surcharge ===
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G (integration example)");

  // === Enchantment threshold ===
  it.todo("sword with enchantment 4 (not cursed) → no high-ench surcharge, premium 115 G");
  it.todo("sword with enchantment 5 (not cursed) → premium 148 G (100 + 30 high-ench + 13 first(rounded up) + 5 fee)");
  it.todo("cursed sword with enchantment 5 → both surcharges apply: base 100 + 50 curse + 30 high-ench = 180; +18 first + 5 fee = 203 G");

  // === Loyalty discount threshold ===
  it.todo("customer with exactly 2 years, one plain sword → premium 93 G (100 base + 10 first - 20 loyalty = 90 + 5 fee = 95, wait recalc) [loyalty discount applies at exactly 2]");

  // === Multi-item modifier scope ===
  it.todo("policy with cursed sword + plain amulet, new customer → base 100+60=160; curse 50 (item-only); pre-fee 210; first-ins 21; pre-fee 231; +5 fee = 236 G");

  // === Follow-up contract discount ===
  it.todo("long-standing customer's second contract (3 yrs, cursed sword ench 7) → premium 160 G (integration example)");

  // === Rounding in MHPCO favor ===
  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");

  // === Quote error handling ===
  it.todo("quote with unknown item type (broomstick) → CLI exits non-zero with stderr error, no results on stdout");

  // === Simple claims ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (insurance 250), damage 200 G → payout 100 G (200 - 100 deductible)");

  // === Enchantment threshold for claim ===
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible: 500-100)");

  // === Dragon material full reimbursement ===
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full then deductible: 800-100)");

  // === Both clauses interact (high-ench wins) ===
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible: 500-100)");
  it.todo("dragon-material sword, ench 8 exactly, damage 1000 G → payout 400 G (high-ench applies)");

  // === Deductible per damage event ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (each item gets own deductible: 400+200)");

  // === Multiple items of same type ===
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; each damage entry treated separately");
  it.todo("two-sword policy: dragon attack damages both swords (two entries) → each with own deductible");
  it.todo("claim has more damage entries of a type than policy covers → CLI exits non-zero, claim rejected");

  // === Cap insurance sum ===
  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium modifiers don't raise cap) → cap 2000 G");
  it.todo("policy with sword + 3 runes block → insurance sum 1750 (block discount doesn't affect insurance sum)");

  // === Cap exhaustion across claims ===
  it.todo("sword cap 2000; first claim of 1500 → payout 1400, remainingCap 600");
  it.todo("after first claim (cap 600), second claim of 1500 → payout 600, remainingCap 0");

  // === Payout rounding ===
  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");

  // === Claim error handling ===
  it.todo("claim references item not in policy (amulet when only sword insured) → CLI exits non-zero with stderr error");
  it.todo("claim references unknown item type → CLI exits non-zero with stderr error");
  it.todo("claim with negative damage amount → CLI exits non-zero with stderr error");

  // === Multi-step scenarios ===
  it.todo("scenario from spec schema example: amulet quote + amulet fire claim 200 → premium and payout integers");
});

