import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest quote cases ===
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // === Base premiums for main items ===
  it("single sword (steel, ench 3, not cursed), new customer → premium 115 G (100 + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single amulet (plain), new customer → premium 71 G (60 + 6 first + 5 fee)");
  it.todo("single staff (plain), new customer → premium 93 G (80 + 8 first + 5 fee)");
  it.todo("single potion (plain), new customer → premium 49 G (40 + 4 first + 5 fee)");

  // === Component base premiums and building block ===
  it.todo("2 runes (new customer) → premium 60 G (50 + 5 first + 5 fee)");
  it.todo("3 runes - block applies (new customer) → premium 71 G (60 + 6 first + 5 fee)");
  it.todo("4 runes - no block, requires exactly 3 (new customer) → premium 115 G (100 + 10 first + 5 fee)");
  it.todo("7 runes - one block of 3 + 4 singles (new customer) → premium 181 G (60+100 + 16 first + 5 fee)");

  // === Alike components clarification (❓) ===
  it.todo("2 runes + 1 moonstone - no block, different types → premium 88 G (75 + 8 first(rounded up from 7.5) + 5 fee)");
  it.todo("3 runes + 3 moonstones - two separate blocks → premium 137 G (120 + 12 first + 5 fee)");

  // === Cursed surcharge integration (newcomer) ===
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G (100 + 50 curse + 10 first + 5 fee)");

  // === Enchantment threshold ===
  it.todo("sword with enchantment 4, not cursed → premium 115 G (no high-ench surcharge)");
  it.todo("sword with enchantment 5, not cursed → premium 148 G (100 + 30 high-ench + 13 first(rounded up from 13) + 5 fee)");
  it.todo("cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 18 first + 5 fee = 203 G)");

  // === Loyalty discount threshold (exactly 2 years) ===
  it.todo("customer with exactly 2 years, plain sword → premium 95 G (100 + 10 first - 20 loyalty + 5 fee)");

  // === Multi-item modifier scope clarification (❓) ===
  it.todo("policy with cursed sword + plain amulet, new customer → premium 231 G (160 + 50 curse(item-only) + 16 first + 5 fee)");

  // === Follow-up contract discount integration ===
  it.todo("long-standing customer 2nd contract (3 yrs, cursed sword ench 7) → premium 160 G (per integration example)");

  // === Rounding in MHPCO favor for premium ===
  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");

  // === Quote error handling ===
  it.todo("quote with unknown item type (broomstick) → CLI exits non-zero, stderr error, no results stdout");

  // === Simple claims (no special clauses) ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("damage to rune (insurance 250), damage 200 G → payout 100 G (200 - 100 deductible)");

  // === High-enchantment clause for claim ===
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% = 500, then -100 deductible)");

  // === Dragon material clause ===
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full reimburse, then -100)");

  // === Both clauses interact (50% wins) ===
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then -100)");
  it.todo("dragon-material sword, ench 8 exactly, damage 1000 G → payout 400 G (high-ench applies)");

  // === Deductible per damage event ===
  it.todo("dragon attack: sword(500) + amulet(300) → total payout 600 G (each item own deductible: 400+200)");

  // === Multiple items of same type clarification (❓) ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: two sword damage entries → each treated separately with own deductible");
  it.todo("claim has more damage entries of type than policy covers → CLI exits non-zero, whole claim rejected");

  // === Cap insurance sum rules ===
  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (modifiers don't raise cap)");
  it.todo("policy with sword + 3 runes block → insurance sum 1750 G (block discount only affects premium)");

  // === Cap exhaustion across claims ===
  it.todo("sword cap 2000; first claim 1500 → payout 1400, remainingCap 600");
  it.todo("sword after first claim (cap 600); second claim 1500 → payout 600, remainingCap 0");

  // === Payout rounding ===
  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");

  // === Claim error handling ===
  it.todo("claim references item not in policy (amulet when sword insured) → CLI exits non-zero, stderr error");
  it.todo("claim references unknown item type → CLI exits non-zero, stderr error");
  it.todo("claim with negative damage amount → CLI exits non-zero, stderr error");
});

