type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function runScenario(input: Scenario): { results: Array<{ premium: number }> } {
  const results = input.steps.map((step) => {
    let policyBase = 0;
    for (const item of step.items) {
      policyBase += BASE_PREMIUM[item.type];
    }
    const firstInsurance = Math.ceil(policyBase * 0.1);
    const premium = policyBase + firstInsurance + 5;
    return { premium };
  });
  return { results };
}

